from agno import Agent
from agno.tools import DuckDuckGo

class CostOptimizedAgent(Agent):
    def __init__(self, **kwargs):
        super().__init__(**kwargs)
        self.max_tool_iterations = 2
        self.token_budget_per_query = 800

    def run(self, task: str):
        iterations = 0
        total_tokens = 0

        while iterations < self.max_tool_iterations:
            response = super().run(task)
            total_tokens += response.usage.total_tokens

            if total_tokens > self.token_budget_per_query:
                return self._finalize_response(response)

            iterations += 1
        return response

    def _finalize_response(self, response):
        return self.llm.run(f'Summarize: {response.content}', max_tokens=200)

# Usage - 60% token reduction
optimized_agent = CostOptimizedAgent(tools=[DuckDuckGo()])

from agno.teams import Team
from typing import Dict, Any

class CachedTeam(Team):
    def __init__(self, **kwargs):
        super().__init__(**kwargs)
        self._research_cache: Dict[str, Any] = {}

    def run(self, task: str):
        # Check cache first
        if task in self._research_cache:
            print('📚 Using cached research')
            return self._research_cache[task]

        # Team execution
        result = super().run(task)
        self._research_cache[task] = result

        # Limit cache size
        if len(self._research_cache) > 10:
            self._research_cache.pop(next(iter(self._research_cache)))

        return result

# Usage - eliminates 70% team redundancy
research_team = CachedTeam(agents={'web': web_agent, 'code': code_agent})
